class Solution {
    public int getKth(int lo, int hi, int k) {
        int[][] powers = new int[hi - lo + 1][2];
        for (int i = 0; i <= hi - lo; i++) {
            powers[i][0] = getPower(lo + i);
            powers[i][1] = lo + i;
        }
        Arrays.sort(powers, (a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]);
        return powers[k - 1][1];
    }

    private int getPower(int x) {
        int power = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            power++;
        }
        return power;
    }
}
